package com.ecoPedal.backend.entity;import com.ecoPedal.backend.entity.enums.TypePoint;import jakarta.persistence.*;import lombok.*;import java.time.LocalDateTime;@Getter@Setter@NoArgsConstructor@AllArgsConstructor@Entity@Table(name = "point_historique")public class PointHistorique {    @Id    @GeneratedValue(strategy = GenerationType.IDENTITY)    private Long id;    @Column(nullable = false)    private Integer points;    @Enumerated(EnumType.STRING)    private TypePoint type;    private String description;    @Column(nullable = false)    private LocalDateTime dateCreation = LocalDateTime.now();    @ManyToOne    @JoinColumn(name = "id_utilisateur", nullable = false)    private Utilisateur utilisateur;    @ManyToOne    @JoinColumn(name = "id_echange", nullable = true)    private Echange echange;    @ManyToOne    @JoinColumn(name= "id_participation" , nullable = true)    private Participation participation;}